518	            }
519	
520	            NDS_VEC_VSETVLI_E32_M2(vl, colCnt);     //note the avl here
521	            NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V2, NDS_VEC_V0);
522	            //move vr results to gpr
523	            NDS_VEC_VMV_X_S(sum, NDS_VEC_V0);
524	
525	            sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
526	            *pOut++ = NDS_ISA_SATS((sum >> post_rshift), 8);
527	        }
528	    }
529	#endif
530	#elif defined(ENA_DSP_ISA_V5)
531	    unsigned long   i_out_y, i_out_x;
532	    unsigned long   i_ch_out;
533	
534	    /* -----------------------
535	     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
536	     *  im2col are done to output in q15_t format from q7_t input
537	     */
538	
539	    q7_t     *pBuffer = (q7_t*)in_tmp_buf;
540	    q7_t     *pOut = out_tensor;
541	
542	    for (i_out_y = 0; i_out_y < out_tensor_dim_y; i_out_y++)
543	    {
544	        for (i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
545	        {
546	            /* This part implements the im2col function */
547	            nn_dup_s8((q7_t *) in_tensor + (i_out_y * in_tensor_dim_x + i_out_x) * in_tensor_ch, pBuffer, in_tensor_ch);
548	            pBuffer += in_tensor_ch;
549	
550	            if (pBuffer == (q7_t*)in_tmp_buf + 2 * in_tensor_ch * ker_dim_x * ker_dim_y)
551	            {
552	                pOut = nn_mat_mul_kernel_q7_bias_2sft(ker_weight,
553	                                                      (q7_t*)in_tmp_buf,
554	                                                      out_tensor_ch,
555	                                                      in_tensor_ch,
556	                                                      pre_rshift,
557	                                                      out_scale,
558	                                                      post_rshift,
559	                                                      bias,
560	                                                      pOut);
