562	                pBuffer = (q7_t*)in_tmp_buf;
563	            }
564	        }
565	    }
566	
567	    /* check if there is left-over for compute */
568	#ifdef ENA_DSP_ISA_64
569	    if (pBuffer != (q7_t*)in_tmp_buf)
570	    {
571	        const q7_t *pA = ker_weight;
572	        for (i_ch_out = 0; i_ch_out < out_tensor_ch; i_ch_out++)
573	        {
574	            long     sum = 0;
575	            q7_t     *pB = (q7_t*)in_tmp_buf;
576	
577	            /* basically each time it process 8 entries */
578	            uint16_t  colCnt = in_tensor_ch * ker_dim_x * ker_dim_y >> 3;
