609	    {
610	        const q7_t *pA = ker_weight;
611	        for (i_ch_out = 0; i_ch_out < out_tensor_ch; i_ch_out++)
612	        {
613	            q31_t     sum = *bias++;
614	            q7_t      *pB = (q7_t*)in_tmp_buf;
