705	            }
706	
707	            //since in_tensor_ch is multiple of 4 (input constraints), the
708	            //following codes will not be reached
709	            // colCnt = in_tensor_ch * ker_dim_y * ker_dim_x & 0x3;
710	            // while (colCnt)
711	            // {
712	            //     q7_t      inA1 = *pA++;
713	            //     q15_t     inB1 = *pB++;
714	            //     sum += inA1 * inB1;
715	            //     colCnt--;
716	            // }
717	            sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
718	            *pOut = (q7_t) NDS_DSP_SATS((sum >> post_rshift), 8);
719	            pOut++;
