727	    for (i = 0; i < out_tensor_ch; i++)
728	    {
729	        for (j = 0; j < out_tensor_dim_y; j++)
730	        {
731	            for (k = 0; k < out_tensor_dim_x; k++)
732	            {
733	                conv_out = bias[i];
734	                for (m = 0; m < ker_dim_y; m++)
735	                {
736	                    for (n = 0; n < ker_dim_x; n++)
737	                    {
