746	                                            ker_weight[i * in_tensor_ch * ker_dim_y * ker_dim_x + (m * ker_dim_y + n) * in_tensor_ch + l];
747	                            }
748	                        }
749	                    }
750	                }
751	                conv_out = (conv_out >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
752	                out_tensor[i + (j * out_tensor_dim_x + k) * out_tensor_ch] = NDS_ISA_SATS((conv_out >> post_rshift), 8);
