25	//// Convolution Functions
26	
27	int32_t riscv_nn_conv_1x1_HWC_u8_s8_s8_sym_bias_fast_any(const u8_t * in_tensor,
28	                                                    const uint16_t in_tensor_dim_x,
29	                                                    const uint16_t in_tensor_dim_y,
30	                                                    const uint16_t in_tensor_ch,
31	                                                    const q7_t * ker_weight,
32	                                                    const uint16_t out_tensor_ch,
33	                                                    const uint16_t ker_dim_x,
34	                                                    const uint16_t ker_dim_y,
35	                                                    const uint16_t pad_x,
36	                                                    const uint16_t pad_y,
37	                                                    const uint16_t stride_x,
38	                                                    const uint16_t stride_y,
39	                                                    const q31_t * bias,
40	                                                    const uint16_t pre_rshift,
41	                                                    const uint16_t out_scale,
42	                                                    const uint16_t post_rshift,
43	                                                    q7_t * out_tensor,
44	                                                    const uint16_t out_tensor_dim_x,
45	                                                    const uint16_t out_tensor_dim_y,
46	                                                    q15_t * in_tmp_buf)
47	{
48	#ifdef ENA_EMPTY_FUN
49	    //empty body
50	#else
51	    if (in_tensor_ch % 4 != 0 || out_tensor_ch % 2 != 0 || ker_dim_x != 1 || ker_dim_y != 1
52	            || pad_x != 0 || pad_y != 0 || stride_x != 1 || stride_y != 1)
53	    {
54	        /* check if the input dimension meets the constraints */
55	        return -1;
56	    }
57	
58	#ifdef ENA_VEC_ISA
59	#if (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_TILING)
60	    //cache is 512KB, type is u8/q7
61	    uint32_t tiling_size = 256;
62	    unsigned long addr_in_tmp_buf;
63	    q7_t *pOut = out_tensor;
64	    u8_t *src_buf = (u8_t *) in_tensor;
65	    q31_t *dst_q31;
66	
67	    const long align_byte = 64;
68	    addr_in_tmp_buf = (unsigned long)in_tmp_buf;
69	    addr_in_tmp_buf += sizeof(*ker_weight) * out_tensor_ch * in_tensor_ch;
70	    addr_in_tmp_buf = nn_align(addr_in_tmp_buf, align_byte);
71	    dst_q31 = (q31_t *)addr_in_tmp_buf;
72	
73	    //transpose the kernel_weight for matrix multiplication
74	    nn_mat_mul_kernel_tiling_transpose_q7(ker_weight, (q7_t *)in_tmp_buf, out_tensor_ch, in_tensor_ch);
75	
76	    pOut = nn_mat_mul_kernel_tiling_bias_u8_s8_s8(src_buf,
77	                                                  (q7_t *)in_tmp_buf,
78	                                                  dst_q31,
79	                                                  pOut,
80	                                                  in_tensor_dim_x * in_tensor_dim_y,
81	                                                  in_tensor_ch,
82	                                                  out_tensor_ch,
83	                                                  pre_rshift,
84	                                                  out_scale,
85	                                                  post_rshift,
86	                                                  bias,
87	                                                  tiling_size);
88	#elif defined(ENA_NDS_V5_VEC_DOT_PROD) && (NDS_VEC_RVV_VERSION >= 100) && (ENA_VEC_INTRINSIC)
89	    unsigned long i_ch_out;
90	    q7_t *pOut = out_tensor;
91	    unsigned long vl;
92	
93	    unsigned long out_tensor_length = (out_tensor_dim_y * out_tensor_dim_x) >> 2;   //ignore in_ch
94	    u8_t *src_buf = (u8_t *)in_tensor;
95	    while(out_tensor_length-- > 0)
96	    {
97	        pOut = nn_mat_mul_kernel_u8_q7_bias_2sft_unroll4(ker_weight,
98	                                                         src_buf,
99	                                                         out_tensor_ch,
100	                                                         in_tensor_ch,
101	                                                         pre_rshift,
102	                                                         out_scale,
103	                                                         post_rshift,
104	                                                         bias,
105	                                                         pOut);
106	        src_buf += 4 * in_tensor_ch;
107	    }
108	
109	    vl = __riscv_vsetvl_e32m1(1);
110	    vint32m1_t vZero = __riscv_vand(__riscv_vundefined_i32m1(), 0, vl);   //const zero for redsum
111	
112	    /* check if there is left-over for compute */
113	    long rest = (out_tensor_dim_y * out_tensor_dim_x) & 0x3;
114	    while(rest-- > 0)
115	    {
116	        const q7_t *p_wt = ker_weight;
117	        const q31_t *bias2 = bias;
118	        uint16_t  colCnt = in_tensor_ch;
119	
120	        for (i_ch_out = 0; i_ch_out < out_tensor_ch; i_ch_out++)
121	        {
122	            u8_t  *p_in = src_buf;
123	            unsigned long colCnt2 = colCnt;
124	
125	            //clear v0~v7
126	            vl = __riscv_vsetvl_e32m8(colCnt);
127	            vint32m8_t vAccumulator = __riscv_vand(__riscv_vundefined_i32m8(), 0x0, vl);
128	
129	            while(colCnt2 > 0)
130	            {
131	                vl = __riscv_vsetvl_e8m8(colCnt2);
132	                //load src1
133	                vint8m8_t vP_wt_i8m8 = __riscv_vle8_v_i8m8(p_wt, vl);
134	                //load src2
135	                vuint8m8_t vP_in_i8m8 = __riscv_vle8_v_u8m8(p_in, vl);
136	                //bump pointers and update loop counter
137	                colCnt2 -= vl;
138	                p_wt += vl;
139	                p_in += vl;
140	                //set the proper avl/SEW/LMUL values for vd4dot
141	                vl >>= 2;
142	                vl = __riscv_vsetvl_e32m8(vl);
143	                //acc += src1 * src2
144	                vAccumulator = __riscv_vd4dotsu_vv_i32m8(vAccumulator, vP_wt_i8m8, vP_in_i8m8, vl);
145	            }
146	
147	            vl = __riscv_vsetvl_e32m8(colCnt);    //note the avl here
148	            vint32m1_t vSum = __riscv_vredsum(vAccumulator , vZero, vl);
149	
150	            //load bias
151	            vl = __riscv_vsetvl_e32m1(1);
152	            vint32m1_t vBias2 = __riscv_vle32_v_i32m1(bias2, vl);
153	            bias2 += vl;
154	
155	            //add bias to acc
156	            vSum = __riscv_vadd(vSum, vBias2, vl);
157	
158	            //2-stage shift
159	            vSum = __riscv_vsra(vSum, pre_rshift, vl);
160	            vSum = __riscv_vmul(vSum, out_scale, vl);
161	            vSum = __riscv_vadd(vSum, NN_ROUND(post_rshift), vl);
162	
163	            //saturate into 8-bits
164	            vl = __riscv_vsetvl_e16mf2(1);     //1: 1 acc
165	            vint16mf2_t vpOut_i16mf2 = __riscv_vnsra(vSum, post_rshift, vl);
166	            vl = __riscv_vsetvl_e8mf4(1);      //1: 1 acc
167	            vint8mf4_t vpOut = __riscv_vnclip(vpOut_i16mf2, 0, __RISCV_VXRM_RNU, vl);
168	
169	            //store the results
170	            __riscv_vse8(pOut, vpOut, vl);
171	            pOut += vl;
172	        }
173	        src_buf += in_tensor_ch;
174	    }
175	#elif defined(ENA_NDS_V5_VEC_DOT_PROD) && (NDS_VEC_RVV_VERSION >= 100)
176	    unsigned long i_ch_out;
177	    q7_t *pOut = out_tensor;
178	    unsigned long vl;
179	
180	    unsigned long out_tensor_length = (out_tensor_dim_y * out_tensor_dim_x) >> 2;   //ignore in_ch
181	    u8_t *src_buf = (u8_t *)in_tensor;
182	    while(out_tensor_length-- > 0)
183	    {
184	        pOut = nn_mat_mul_kernel_u8_q7_bias_2sft_unroll4(ker_weight,
185	                                                         src_buf,
186	                                                         out_tensor_ch,
187	                                                         in_tensor_ch,
188	                                                         pre_rshift,
189	                                                         out_scale,
190	                                                         post_rshift,
191	                                                         bias,
192	                                                         pOut);
193	        src_buf += 4 * in_tensor_ch;
194	    }
195	
196	    NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
197	    NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);   //const zero for redsum
198	
199	    /* check if there is left-over for compute */
200	    long rest = (out_tensor_dim_y * out_tensor_dim_x) & 0x3;
201	    while(rest-- > 0)
202	    {
203	        const q7_t *p_wt = ker_weight;
204	        const q31_t *bias2 = bias;
205	        uint16_t  colCnt = in_tensor_ch;
206	
207	        for (i_ch_out = 0; i_ch_out < out_tensor_ch; i_ch_out++)
208	        {
209	            u8_t  *p_in = src_buf;
210	            unsigned long colCnt2 = colCnt;
211	
212	            //clear v0~v7
213	            NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
214	            NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0x0);
215	
216	            while(colCnt2 > 0)
217	            {
218	                NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
219	                //load src1
220	                NDS_VEC_VLB_V(NDS_VEC_V8, p_wt);
221	                //load src2
222	                NDS_VEC_VLB_V(NDS_VEC_V16, p_in);
223	                //bump pointers and update loop counter
224	                colCnt2 -= vl;
225	                p_wt += vl;
226	                p_in += vl;
227	                //set the proper avl/SEW/LMUL values for vd4dot
228	                vl >>= 2;
229	                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
230	                //acc += src1 * src2
231	                NDS_VEC_VD4DOTSU_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
232	            }
233	
234	            NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);    //note the avl here
235	            NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V31);
236	
237	            //load bias
238	            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
239	            NDS_VEC_VLW_V(NDS_VEC_V30, bias2);
240	            bias2 += vl;
241	
242	            //add bias to acc
243	            NDS_VEC_VADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V30);
244	
