503	            nn_dup_s8((q7_t *) in_tensor + (i_out_y * in_tensor_dim_x + i_out_x) * in_tensor_ch, pBuffer, in_tensor_ch);
504	            pBuffer += in_tensor_ch;
505	
506	            if (pBuffer == (q7_t *)in_tmp_buf + 2 * in_tensor_ch * ker_dim_x * ker_dim_y)
507	            {
508	                pOut = nn_mat_mul_kernel_q7_q15_bias_2sft(ker_weight,
509	                                                          (q7_t *)in_tmp_buf,
510	                                                          out_tensor_ch,
511	                                                          in_tensor_ch,
512	                                                          pre_rshift,
513	                                                          out_scale,
514	                                                          post_rshift,
515	                                                          bias,
516	                                                          pOut);
517	                /* counter reset */
518	                pBuffer = (q7_t*)in_tmp_buf;
519	            }
520	        }
521	    }
522	#ifdef ENA_DSP_ISA_64 //V5 64, DX25
523	    if (pBuffer != (q7_t*)in_tmp_buf)
524	    {
525	        const q7_t *pA = ker_weight;
526	
527	        for (i_ch_out = 0; i_ch_out < out_tensor_ch; i_ch_out++)
528	        {
529	            long sum = 0;
530	            q7_t *pB = (q7_t *)in_tmp_buf;
531	
532	            uint16_t  colCnt = in_tensor_ch * ker_dim_x * ker_dim_y >> 3;
533	            while (colCnt)
534	            {
535	                long inA1, inB1;
536	
537	                inA1 = *__SIMD64(pA)++;
538	                inB1 = *__SIMD64(pB)++;
539	                sum  = NDS_DSP_SMAQA(sum, inA1, inB1);
540	                colCnt--;
541	            }
542	
543	            //sum up the high and low part results (SIMD results)
544	            sum = PADD_S32(sum);
545	
546	            // Remainder
547	            colCnt = in_tensor_ch * ker_dim_y * ker_dim_x & 0x7;
548	            while (colCnt)
549	            {
550	                q7_t inA1 = *pA++;
551	                q7_t inB1 = *pB++;
552	                sum += inA1 * inB1;
553	                colCnt--;
554	            }
555	
556	            sum += bias[i_ch_out];
557	            sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
558	            *pOut++ = NDS_DSP_SATS((sum >> post_rshift), 16);
559	        }
560	    }
561	#else //V5 32, D25
562	    if (pBuffer != (q7_t*)in_tmp_buf)
563	    {
564	        const q7_t *pA = ker_weight;
565	
566	        for (i_ch_out = 0; i_ch_out < out_tensor_ch; i_ch_out++)
567	        {
568	            q31_t sum = bias[i_ch_out];
569	            q7_t *pB = (q7_t *)in_tmp_buf;
570	
571	            uint16_t  colCnt = in_tensor_ch * ker_dim_x * ker_dim_y >> 2;
572	            while (colCnt)
573	            {
574	                // SMAQA
575	                long     inA1;
576	                q31_t     inB1 = *__SIMD32(pB)++;
577	                inA1 = *__SIMD32(pA)++;
578	                sum  = NDS_DSP_SMAQA(sum,  inA1, inB1);
579	                colCnt--;
580	            }
581	
582	            // Remainder
583	            //since in_tensor_ch is multiple of 4 (input constraints), the
584	            //following codes will not be reached
585	            // colCnt = in_tensor_ch * ker_dim_y * ker_dim_x & 0x3;
586	            // while (colCnt)
587	            // {
588	            //     q7_t inA1 = *pA++;
589	            //     q7_t inB1 = *pB++;
590	            //     sum += inA1 * inB1;
591	            //     colCnt--;
592	            // }
593	            // NDS_NN_TRUNCATE
594	            sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
595	            *pOut++ = NDS_ISA_SATS((sum >> post_rshift), 16);
596	        }
597	    }
598	#endif
599	#elif defined(ENA_DSP_ISA)
600	    unsigned long   i_out_y, i_out_x;
601	    unsigned long   i_ch_out;
602	
603	    /* -----------------------
604	     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
605	     *  im2col are done to output in q15_t format from q7_t input
606	     */
607	
608	    q15_t    *pBuffer = in_tmp_buf;
609	    q15_t    *pOut = out_tensor;
610	
611	    for (i_out_y = 0; i_out_y < out_tensor_dim_y; i_out_y++)
612	    {
613	        for (i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
614	        {
615	            /* This part implements the im2col function */
616	            nn_dup_s8_s16_reordered((q7_t *) in_tensor + (i_out_y * in_tensor_dim_x + i_out_x) * in_tensor_ch,
617	                                        pBuffer, in_tensor_ch);
618	            pBuffer += in_tensor_ch;
619	
620	            if (pBuffer == in_tmp_buf + 2 * in_tensor_ch * ker_dim_x * ker_dim_y)
621	            {
622	                pOut = nn_mat_mul_kernel_q7_q15_q15_reordered_bias_2sft(ker_weight,
623	                                                                        in_tmp_buf,
624	                                                                        out_tensor_ch,
625	                                                                        in_tensor_ch,
626	                                                                        pre_rshift,
627	                                                                        out_scale,
628	                                                                        post_rshift,
629	                                                                        bias,
630	                                                                        pOut);
631	                /* counter reset */
632	                pBuffer = in_tmp_buf;
633	            }
634	        }
635	    }
636	
637	    /* check if there is left-over for compute */
638	    if (pBuffer != in_tmp_buf)
639	    {
640	        const q7_t *pA = ker_weight;
641	        for (i_ch_out = 0; i_ch_out < out_tensor_ch; i_ch_out++)
642	        {
643	            q31_t     sum = bias[i_ch_out];
644	            q15_t    *pB = in_tmp_buf;
645	
646	            /* basically each time it process 4 entries */
647	            uint16_t  colCnt = in_tensor_ch * ker_dim_x * ker_dim_y >> 2;
648	
649	            while (colCnt)
650	            {
651	                q31_t     inA1, inA2;
652	                q31_t     inB1, inB2;
653	
654	                pA = (const q7_t *)read_and_pad_reordered((void *)pA, &inA1, &inA2);
655	                inB1 = *__SIMD32(pB)++;
656	                sum = NDS_DSP_KMADA(sum, inA1, inB1);
657	                inB2 = *__SIMD32(pB)++;
658	                sum = NDS_DSP_KMADA(sum, inA2, inB2);
659	                colCnt--;
660	            }
661	
662	            //since in_tensor_ch is multiple of 4 (input constraints), the
663	            //following codes will not be reached
664	            // colCnt = in_tensor_ch * ker_dim_y * ker_dim_x & 0x3;
665	            // while (colCnt)
666	            // {
667	            //     q7_t      inA1 = *pA++;
668	            //     q15_t     inB1 = *pB++;
669	            //     sum += inA1 * inB1;
670	            //     colCnt--;
671	            // }
672	            sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
673	            *pOut = NDS_DSP_SATS((sum >> post_rshift), 16);
674	            pOut++;
675	        }
676	    }
677	#else // general
678	    int       i, j, k, l, m, n;
679	    int       conv_out;
680	    int       in_row, in_col;
681	
682	    for (i = 0; i < out_tensor_ch; i++)
683	    {
684	        for (j = 0; j < out_tensor_dim_y; j++)
685	        {
686	            for (k = 0; k < out_tensor_dim_x; k++)
687	            {
688	                conv_out = bias[i];
689	                for (m = 0; m < ker_dim_y; m++)
690	                {
691	                    for (n = 0; n < ker_dim_x; n++)
692	                    {
693	                        // if-for implementation
694	                        in_row = stride_y * j + m - pad_y;
695	                        in_col = stride_x * k + n - pad_x;
696	                        if (in_row >= 0 && in_col >= 0 && in_row < in_tensor_dim_y && in_col < in_tensor_dim_x)
697	                        {
698	                            for (l = 0; l < in_tensor_ch; l++)
699	                            {
700	                                conv_out += in_tensor[(in_row * in_tensor_dim_x + in_col) * in_tensor_ch + l] *
701	                                            ker_weight[i * in_tensor_ch * ker_dim_y * ker_dim_x + (m * ker_dim_y + n) * in_tensor_ch + l];
702	                            }
703	                        }
704	                    }
705	                }
706	                conv_out = (conv_out >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
707	                out_tensor[i + (j * out_tensor_dim_x + k) * out_tensor_ch] = NDS_ISA_SATS((conv_out >> post_rshift), 16);
708	            }
709	        }
710	    }
711	#endif  //ENA_DSP_ISA
712	#endif  //ENA_EMPTY_FUN
713	
714	    /* Return to application */
715	    return 0;
716	}
