547	        for (i_ch_out = 0; i_ch_out < out_tensor_ch; i_ch_out++)
548	        {
549	            q31_t     sum = 0;
550	            u8_t      *pB = (u8_t*)in_tmp_buf;
551	            uint16_t colCnt2 = colCnt >> 2;
552	
553	            while(colCnt2)
554	            {
555	                q31_t inA1 = *__SIMD32(pA)++;
556	                u32_t inB1 = *__SIMD32(pB)++;
557	                sum = NDS_DSP_SMAQA_SU(sum, inA1, inB1);
558	                colCnt2--;
559	            }
560	
561	            //since in_tensor_ch is multiple of 4 (input constraints), the
562	            //following codes will not be reached
563	            // colCnt2 = colCnt & 0x3;
564	            // while (colCnt2)
565	            // {
566	            //     q7_t	inA1 = *pA++;
567	            //     u8_t	inB1 = *pB++;
568	            //     sum += inA1 * inB1;
569	            //     colCnt2--;
570	            // }
571	
572	            sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
573	            *pOut++ = NDS_ISA_SAT((sum >> post_rshift), 8);
574	        }
575		}
576	#endif
577	#elif defined(ENA_DSP_ISA)
578	    unsigned long   i_out_y, i_out_x;
579	    unsigned long   i_ch_out;
580	
581	    /* -----------------------
582	     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
583	     *  im2col are done to output in q15_t format from q7_t input
584	     */
585	
586	    u16_t    *pBuffer = (u16_t*)in_tmp_buf;
587	    u8_t     *pOut = out_tensor;
588	
589	    for (i_out_y = 0; i_out_y < out_tensor_dim_y; i_out_y++)
590	    {
591	        for (i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
592	        {
593	            /* This part implements the im2col function */
594	            nn_dup_u8_u16_reordered((u8_t *) in_tensor + (i_out_y * in_tensor_dim_x + i_out_x) * in_tensor_ch,
595	                                        pBuffer, in_tensor_ch);
596	            pBuffer += in_tensor_ch;
597	
598	            if (pBuffer == (u16_t*)in_tmp_buf + 2 * in_tensor_ch * ker_dim_x * ker_dim_y)
599	            {
600	                pOut = nn_mat_mul_kernel_q7_u16_u8_reordered_2sft(ker_weight,
601	                                                                  (u16_t*)in_tmp_buf,
602	                                                                  out_tensor_ch,
603	                                                                  in_tensor_ch,
604	                                                                  pre_rshift,
605	                                                                  out_scale,
606	                                                                  post_rshift,
607	                                                                  pOut);
608	                /* counter reset */
609	                pBuffer = (u16_t*)in_tmp_buf;
610	            }
611	        }
612	    }
613	
614	    /* check if there is left-over for compute */
615	    if (pBuffer != (u16_t*)in_tmp_buf)
616	    {
617	        const q7_t *pA = ker_weight;
618	        for (i_ch_out = 0; i_ch_out < out_tensor_ch; i_ch_out++)
619	        {
620	            q31_t     sum = 0;
621	            u16_t    *pB = (u16_t*)in_tmp_buf;
622	
623	            /* basically each time it process 4 entries */
624	            uint16_t  colCnt = in_tensor_ch * ker_dim_x * ker_dim_y >> 2;
625	
626	            while (colCnt)
627	            {
628	                q31_t     inA1, inA2;
629	                q31_t     inB1, inB2;
630	
631	                pA = (const q7_t *)read_and_pad_reordered((void *)pA, &inA1, &inA2);
632	                inB1 = *__SIMD32(pB)++;
633	                sum = NDS_DSP_KMADA(sum, inA1, inB1);
634	                inB2 = *__SIMD32(pB)++;
635	                sum = NDS_DSP_KMADA(sum, inA2, inB2);
636	                colCnt--;
637	            }
638	
639	            //since in_tensor_ch is multiple of 4 (input constraints), the
640	            //following codes will not be reached
641	            // colCnt = in_tensor_ch * ker_dim_y * ker_dim_x & 0x3;
642	            // while (colCnt)
643	            // {
644	            //     q7_t      inA1 = *pA++;
645	            //     q15_t     inB1 = *pB++;
646	            //     sum += inA1 * inB1;
647	            //     colCnt--;
648	            // }
649	            sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
650	            *pOut = NDS_DSP_SAT((sum >> post_rshift), 8);
651	            pOut++;
652	        }
653	    }
654	#else // general
655	    int       i, j, k, l, m, n;
656	    int       conv_out;
657	    int       in_row, in_col;
658	
659	    for (i = 0; i < out_tensor_ch; i++)
660	    {
661	        for (j = 0; j < out_tensor_dim_y; j++)
662	        {
663	            for (k = 0; k < out_tensor_dim_x; k++)
664	            {
665	                conv_out = 0;
666	                for (m = 0; m < ker_dim_y; m++)
667	                {
668	                    for (n = 0; n < ker_dim_x; n++)
669	                    {
670	                        // if-for implementation
671	                        in_row = stride_y * j + m - pad_y;
672	                        in_col = stride_x * k + n - pad_x;
673	                        if (in_row >= 0 && in_col >= 0 && in_row < in_tensor_dim_y && in_col < in_tensor_dim_x)
674	                        {
675	                            for (l = 0; l < in_tensor_ch; l++)
676	                            {
677	                                conv_out += in_tensor[(in_row * in_tensor_dim_x + in_col) * in_tensor_ch + l] *
678	                                            ker_weight[i * in_tensor_ch * ker_dim_y * ker_dim_x + (m * ker_dim_y + n) * in_tensor_ch + l];
679	                            }
680	                        }
681	                    }
682	                }
683	                if(conv_out < 0)
684	                    out_tensor[i + (j * out_tensor_dim_x + k) * out_tensor_ch] = 0;
685	                else
686	                {
687	                    conv_out = (conv_out >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
688	                    out_tensor[i + (j * out_tensor_dim_x + k) * out_tensor_ch] = NDS_ISA_SAT((conv_out >> post_rshift), 8);
689	                }
690	            }
691	        }
692	    }
693	#endif
694	#endif  //ENA_EMPTY_FUN
695	
696	    /* Return to application */
697	    return 0;
698	}
