92	    q7_t *src_buf = (q7_t *)in_tensor;
93	    while(out_tensor_length-- > 0)
94	    {
95	        pOut = nn_mat_mul_kernel_q7_2sft_unroll4(ker_weight,
96	                                                 src_buf,
97	                                                 out_tensor_ch,
98	                                                 in_tensor_ch,
99	                                                 pre_rshift,
100	                                                 out_scale,
101	                                                 post_rshift,
102	                                                 pOut);
