155	            vl = __riscv_vsetvl_e8mf4(1);      //1: 1 acc
156	            vint8mf4_t vSum_i8mf4 = __riscv_vnclip(vSum_i16mf2, 0, __RISCV_VXRM_RNU, vl);
157	
158	            //store the results
159	            __riscv_vse8(pOut, vSum_i8mf4, vl);
160	            pOut += vl;
161	        }
162	        src_buf += in_tensor_ch;
163	    }
164	#elif defined(ENA_NDS_V5_VEC_DOT_PROD) && (NDS_VEC_RVV_VERSION >= 100)
165	    unsigned long i_ch_out;
166	    q7_t *pOut = out_tensor;
167	    unsigned long vl;
168	
169	    unsigned long out_tensor_length = (out_tensor_dim_y * out_tensor_dim_x) >> 2;   //ignore in_ch
170	    q7_t *src_buf = (q7_t *)in_tensor;
171	    while(out_tensor_length-- > 0)
