25	//// Convolution Functions
26	
27	int32_t riscv_nn_conv_1x1_HWC_u8_s8_s8_sym_fast_any(const u8_t * in_tensor,
28	                                                const uint16_t in_tensor_dim_x,
29	                                                const uint16_t in_tensor_dim_y,
30	                                                const uint16_t in_tensor_ch,
31	                                                const q7_t * ker_weight,
32	                                                const uint16_t out_tensor_ch,
33	                                                const uint16_t ker_dim_x,
34	                                                const uint16_t ker_dim_y,
35	                                                const uint16_t pad_x,
36	                                                const uint16_t pad_y,
37	                                                const uint16_t stride_x,
38	                                                const uint16_t stride_y,
39	                                                const uint16_t pre_rshift,
40	                                                const uint16_t out_scale,
41	                                                const uint16_t post_rshift,
42	                                                q7_t * out_tensor,
43	                                                const uint16_t out_tensor_dim_x,
44	                                                const uint16_t out_tensor_dim_y,
45	                                                q15_t * in_tmp_buf)
46	{
47	#ifdef ENA_EMPTY_FUN
48	    //empty body
49	#else
50	    if (in_tensor_ch % 4 != 0 || out_tensor_ch % 2 != 0 || ker_dim_x != 1 || ker_dim_y != 1
51	            || pad_x != 0 || pad_y != 0 || stride_x != 1 || stride_y != 1)
52	    {
53	        /* check if the input dimension meets the constraints */
54	        return -1;
55	    }
56	
57	#ifdef ENA_VEC_ISA
58	#if (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_TILING)
59	    //cache is 512KB, type is u8/q7
60	    uint32_t tiling_size = 256;
61	    unsigned long addr_in_tmp_buf;
62	    q7_t *pOut = out_tensor;
63	    u8_t *src_buf = (u8_t *) in_tensor;
64	    q31_t *dst_q31;
65	
66	    const long align_byte = 64;
67	    addr_in_tmp_buf = (unsigned long)in_tmp_buf;
68	    addr_in_tmp_buf += sizeof(*ker_weight) * out_tensor_ch * in_tensor_ch;
69	    addr_in_tmp_buf = nn_align(addr_in_tmp_buf, align_byte);
70	    dst_q31 = (q31_t *)addr_in_tmp_buf;
71	
72	    //transpose the kernel_weight for matrix multiplication
73	    nn_mat_mul_kernel_tiling_transpose_q7(ker_weight, (q7_t *)in_tmp_buf, out_tensor_ch, in_tensor_ch);
74	
75	    pOut = nn_mat_mul_kernel_tiling_u8_s8_s8(src_buf,
76	                                             (q7_t *)in_tmp_buf,
77	                                             dst_q31,
78	                                             pOut,
79	                                             in_tensor_dim_x * in_tensor_dim_y,
80	                                             in_tensor_ch,
81	                                             out_tensor_ch,
82	                                             pre_rshift,
83	                                             out_scale,
84	                                             post_rshift,
85	                                             tiling_size);
86	#elif defined(ENA_NDS_V5_VEC_DOT_PROD) && (NDS_VEC_RVV_VERSION >= 100) && (ENA_VEC_INTRINSIC)
87	    unsigned long i_ch_out;
88	    q7_t *pOut = out_tensor;
89	    unsigned long vl;
90	
91	    unsigned long out_tensor_length = (out_tensor_dim_y * out_tensor_dim_x) >> 2;   //ignore in_ch
92	    u8_t *src_buf = (u8_t *)in_tensor;
93	    while(out_tensor_length-- > 0)
94	    {
95	        pOut = nn_mat_mul_kernel_u8_q7_2sft_unroll4(ker_weight,
96	                                                    src_buf,
97	                                                    out_tensor_ch,
98	                                                    in_tensor_ch,
99	                                                    pre_rshift,
100	                                                    out_scale,
101	                                                    post_rshift,
102	                                                    pOut);
103	        src_buf += 4 * in_tensor_ch;
104	    }
105	
106	    vl = __riscv_vsetvl_e32m1(1);
107	    vint32m1_t vZero = __riscv_vand(__riscv_vundefined_i32m1(), 0, vl);   //const zero for redsum
108	    /* check if there is left-over for compute */
109	    long rest = (out_tensor_dim_y * out_tensor_dim_x) & 0x3;
110	    while(rest-- > 0)
111	    {
112	        const q7_t *p_wt = ker_weight;
113	        uint16_t  colCnt = in_tensor_ch;
114	
115	        for (i_ch_out = 0; i_ch_out < out_tensor_ch; i_ch_out++)
116	        {
117	            u8_t  *p_in = src_buf;
118	            unsigned long colCnt2 = colCnt;
119	
120	            vl = __riscv_vsetvl_e32m8(colCnt);
121	            vint32m8_t vAccumulator = __riscv_vand(__riscv_vundefined_i32m8(), 0x0, vl);
122	
123	            while(colCnt2 > 0)
124	            {
125	                vl = __riscv_vsetvl_e8m8(colCnt2);
126	                //load src1
127	                vint8m8_t vP_wt_i8m8 = __riscv_vle8_v_i8m8(p_wt, vl);
128	                //load src2
129	                vuint8m8_t vP_in_u8m8 = __riscv_vle8_v_u8m8(p_in, vl);
130	                //bump pointers and update loop counter
131	                colCnt2 -= vl;
132	                p_wt += vl;
133	                p_in += vl;
134	                //set the proper avl/SEW/LMUL values for vd4dot
135	                vl >>= 2;
136	                vl = __riscv_vsetvl_e32m8(vl);
137	                //acc += src1 * src2
138	                vAccumulator = __riscv_vd4dotsu_vv_i32m8(vAccumulator, vP_wt_i8m8, vP_in_u8m8, vl);
139	            }
140	
141	            vl = __riscv_vsetvl_e32m8(colCnt);    //note the avl here
142	            vint32m1_t vSum = __riscv_vredsum(vAccumulator, vZero, vl);
143	
144	            //2-stage shift
145	            vl = __riscv_vsetvl_e32m1(1);
