627	                inB2 = *__SIMD32(pB)++;
628	                sum = NDS_DSP_KMADA(sum, inA2, inB2);
629	                colCnt--;
630	            }
631	
632	            //since in_tensor_ch is multiple of 4 (input constraints), the
633	            //following codes will not be reached
634	            // colCnt = in_tensor_ch * ker_dim_y * ker_dim_x & 0x3;
635	            // while (colCnt)
636	            // {
637	            //     q7_t      inA1 = *pA++;
638	            //     q15_t     inB1 = *pB++;
639	            //     sum += inA1 * inB1;
640	            //     colCnt--;
641	            // }
642	            sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
643	            *pOut = NDS_DSP_SATS((sum >> post_rshift), 8);
644	            pOut++;
645	        }
646	    }
647	#else // general
648	    int       i, j, k, l, m, n;
649	    int       conv_out;
650	    int       in_row, in_col;
651	
652	    for (i = 0; i < out_tensor_ch; i++)
653	    {
654	        for (j = 0; j < out_tensor_dim_y; j++)
655	        {
656	            for (k = 0; k < out_tensor_dim_x; k++)
657	            {
658	                conv_out = 0;
659	                for (m = 0; m < ker_dim_y; m++)
660	                {
661	                    for (n = 0; n < ker_dim_x; n++)
662	                    {
663	                        // if-for implementation
664	                        in_row = stride_y * j + m - pad_y;
665	                        in_col = stride_x * k + n - pad_x;
666	                        if (in_row >= 0 && in_col >= 0 && in_row < in_tensor_dim_y && in_col < in_tensor_dim_x)
667	                        {
668	                            for (l = 0; l < in_tensor_ch; l++)
669	                            {
670	                                conv_out += in_tensor[(in_row * in_tensor_dim_x + in_col) * in_tensor_ch + l] *
671	                                            ker_weight[i * in_tensor_ch * ker_dim_y * ker_dim_x + (m * ker_dim_y + n) * in_tensor_ch + l];
672	                            }
673	                        }
674	                    }
675	                }
676	                conv_out = (conv_out >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
677	                out_tensor[i + (j * out_tensor_dim_x + k) * out_tensor_ch] = NDS_ISA_SATS((conv_out >> post_rshift), 8);
678	            }
679	        }
680	    }
681	#endif
682	#endif  //ENA_EMPTY_FUN
683	
684	    /* Return to application */
685	    return 0;
686	}
