128	                //load src1
129	                vint8m8_t vP_wt_i8m8 = __riscv_vle8_v_i8m8(p_wt, vl);
130	                //load src2
131	                vuint8m8_t vP_in_u8m8 = __riscv_vle8_v_u8m8(p_in, vl);
132	                //bump pointers and update loop counter
133	                colCnt2 -= vl;
134	                p_wt += vl;
135	                p_in += vl;
