432	        for (i_ch_out = 0; i_ch_out < out_tensor_ch; i_ch_out++)
433	        {
434	            q31_t     sum = 0;
435	            u8_t      *pB = (u8_t*)in_tmp_buf;
436	            uint16_t colCnt2 = colCnt;
