460	            //move vr results to gpr
461	            NDS_VEC_VMV_X_S(sum, NDS_VEC_V0);
462	
463	            sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
464	            *pOut++ = NDS_ISA_SATS((sum >> post_rshift), 16);
465	        }
466	    }
