39	                                                const uint16_t pre_rshift,
40	                                                const uint16_t out_scale,
41	                                                const uint16_t post_rshift,
42	                                                q15_t * out_tensor,
43	                                                const uint16_t out_tensor_dim_x,
44	                                                const uint16_t out_tensor_dim_y,
45	                                                q15_t * in_tmp_buf)
46	{
47	#ifdef ENA_EMPTY_FUN
48	    //empty body
49	#else
50	    if (in_tensor_ch % 4 != 0 || out_tensor_ch % 2 != 0 || ker_dim_x != 1 || ker_dim_y != 1
51	            || pad_x != 0 || pad_y != 0 || stride_x != 1 || stride_y != 1)
52	    {
53	        /* check if the input dimension meets the constraints */
54	        return -1;
55	    }
56	
57	#ifdef ENA_VEC_ISA
58	#if (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_TILING)
59	    //cache is 512KB, type is q7
60	    uint32_t tiling_size = 256;
61	    unsigned long addr_in_tmp_buf;
62	    q15_t *pOut = out_tensor;
63	    q7_t *src_buf = (q7_t *) in_tensor;
64	    q31_t *dst_q31;
65	
66	    const long align_byte = 64;
67	    addr_in_tmp_buf = (unsigned long)in_tmp_buf;
68	    addr_in_tmp_buf += sizeof(*ker_weight) * out_tensor_ch * in_tensor_ch;
69	    addr_in_tmp_buf = nn_align(addr_in_tmp_buf, align_byte);
70	    dst_q31 = (q31_t *)addr_in_tmp_buf;
71	
72	    //transpose the kernel_weight for matrix multiplication
73	    nn_mat_mul_kernel_tiling_transpose_q7(ker_weight, (q7_t *)in_tmp_buf, out_tensor_ch, in_tensor_ch);
74	
75	    pOut = nn_mat_mul_kernel_tiling_s8_s16_s8(src_buf,
76	                                              (q7_t *)in_tmp_buf,
77	                                              dst_q31,
78	                                              pOut,
79	                                              in_tensor_dim_x * in_tensor_dim_y,
80	                                              in_tensor_ch,
81	                                              out_tensor_ch,
82	                                              pre_rshift,
83	                                              out_scale,
84	                                              post_rshift,
85	                                              tiling_size);
86	#elif defined(ENA_NDS_V5_VEC_DOT_PROD) && (NDS_VEC_RVV_VERSION >= 100) && (ENA_VEC_INTRINSIC)
87	    unsigned long i_ch_out;
88	    q15_t *pOut = out_tensor;
89	    unsigned long vl;
90	
91	    unsigned long out_tensor_length = (out_tensor_dim_y * out_tensor_dim_x) >> 2;   //ignore in_ch
92	    q7_t *src_buf = (q7_t *)in_tensor;
93	    while(out_tensor_length-- > 0)
94	    {
95	        pOut = nn_mat_mul_kernel_q7_q15_2sft_unroll4(ker_weight,
96	                                                     src_buf,
97	                                                     out_tensor_ch,
98	                                                     in_tensor_ch,
99	                                                     pre_rshift,
100	                                                     out_scale,
101	                                                     post_rshift,
102	                                                     pOut);
103	        src_buf += 4 * in_tensor_ch;
104	    }
