106	    vl = __riscv_vsetvl_e32m1(1);
107	    vint32m1_t vZero = __riscv_vand(__riscv_vundefined_i32m1(), 0, vl);   //const zero for redsum
108	
109	    /* check if there is left-over for compute */
110	    long rest = (out_tensor_dim_y * out_tensor_dim_x) & 0x3;
111	    while(rest-- > 0)
112	    {
113	        const q7_t *p_wt = ker_weight;
114	        uint16_t  colCnt = in_tensor_ch;
115	
116	        for (i_ch_out = 0; i_ch_out < out_tensor_ch; i_ch_out++)
117	        {
118	            q7_t  *p_in = src_buf;
119	            unsigned long colCnt2 = colCnt;
120	
121	            //clear v0~v7
122	            vl = __riscv_vsetvl_e32m8(colCnt);
123	            vint32m8_t vAccumulator = __riscv_vand(__riscv_vundefined_i32m8(), 0x0, vl);
124	
125	            while(colCnt2 > 0)
126	            {
127	                vl = __riscv_vsetvl_e8m8(colCnt2);
128	                //load src1
129	                vint8m8_t vP_wt_i8m8 = __riscv_vle8_v_i8m8(p_wt, vl);
130	                //load src2
131	                vint8m8_t vP_in_i8m8 = __riscv_vle8_v_i8m8(p_in, vl);
132	                //bump pointers and update loop counter
133	                colCnt2 -= vl;
134	                p_wt += vl;
135	                p_in += vl;
136	                //set the proper avl/SEW/LMUL values for vd4dot
137	                vl >>= 2;
138	                vl = __riscv_vsetvl_e32m8(vl);
139	                //acc += src1 * src2
140	                vAccumulator = __riscv_vd4dots_vv_i32m8(vAccumulator, vP_in_i8m8, vP_wt_i8m8, vl);
141	            }
142	
143	            vl = __riscv_vsetvl_e32m8(colCnt);    //note the avl here
144	            vint32m1_t vSum = __riscv_vredsum(vAccumulator, vZero, vl);
145	
146	            //2-stage shift
147	            vl = __riscv_vsetvl_e32m1(1);
148	            vSum = __riscv_vsra(vSum, pre_rshift, vl);
149	            vSum = __riscv_vmul(vSum, out_scale, vl);
150	            vSum = __riscv_vadd(vSum, NN_ROUND(post_rshift), vl);
151	
152	            //saturate into 8-bits
153	            vSum = __riscv_vsra(vSum, post_rshift, vl);
154	            vl = __riscv_vsetvl_e16mf2(1);     //1: 1 acc
155	            vint16mf2_t vSum_i16mf2 = __riscv_vnclip(vSum, 0, __RISCV_VXRM_RNU, vl);
156	
157	            //store the results
158	            __riscv_vse16(pOut, vSum_i16mf2, vl);
159	            pOut += vl;
160	        }
161	        src_buf += in_tensor_ch;
162	    }
163	#elif defined(ENA_NDS_V5_VEC_DOT_PROD) && (NDS_VEC_RVV_VERSION >= 100)
164	    unsigned long i_ch_out;
165	    q15_t *pOut = out_tensor;
166	    unsigned long vl;
167	
168	    unsigned long out_tensor_length = (out_tensor_dim_y * out_tensor_dim_x) >> 2;   //ignore in_ch
169	    q7_t *src_buf = (q7_t *)in_tensor;
170	    while(out_tensor_length-- > 0)
171	    {
172	        pOut = nn_mat_mul_kernel_q7_q15_2sft_unroll4(ker_weight,
173	                                                     src_buf,
174	                                                     out_tensor_ch,
175	                                                     in_tensor_ch,
176	                                                     pre_rshift,
177	                                                     out_scale,
178	                                                     post_rshift,
179	                                                     pOut);
180	        src_buf += 4 * in_tensor_ch;
181	    }
182	
183	    NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
184	    NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);   //const zero for redsum
185	
186	    /* check if there is left-over for compute */
187	    long rest = (out_tensor_dim_y * out_tensor_dim_x) & 0x3;
188	    while(rest-- > 0)
189	    {
190	        const q7_t *p_wt = ker_weight;
191	        uint16_t  colCnt = in_tensor_ch;
192	
193	        for (i_ch_out = 0; i_ch_out < out_tensor_ch; i_ch_out++)
194	        {
195	            q7_t  *p_in = src_buf;
196	            unsigned long colCnt2 = colCnt;
197	
198	            //clear v0~v7
199	            NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
200	            NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0x0);
201	
202	            while(colCnt2 > 0)
203	            {
204	                NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
205	                //load src1
206	                NDS_VEC_VLB_V(NDS_VEC_V8, p_wt);
207	                //load src2
208	                NDS_VEC_VLB_V(NDS_VEC_V16, p_in);
209	                //bump pointers and update loop counter
210	                colCnt2 -= vl;
211	                p_wt += vl;
212	                p_in += vl;
213	                //set the proper avl/SEW/LMUL values for vd4dot
