#if (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_TILING)
    //cache is 512KB, type is q7
    uint32_t tiling_size = 256;
    unsigned long addr_in_tmp_buf;
    q7_t *pOut = out_tensor;
    q7_t *src_buf = (q7_t *) in_tensor;
    q31_t *dst_q31;

#ifdef DCACHE_SIZE
    int i;
    int tiling_size_arr[] = { 1,8,16,32,64,128,256,512,1024,2048 };
    int max_tile_size_in_cache = sqrt(((DCACHE_SIZE) << 10) / 6); //sqrt(((DCACHE_SIZE) << 10) / 3 / sizeof(float16_t))
    for (i = 1; i < sizeof(tiling_size_arr) / sizeof(tiling_size_arr[0]); i++)
    {
        if (tiling_size_arr[i] > max_tile_size_in_cache)
        {
            tiling_size = tiling_size_arr[i - 1];
            break;
        }
    }
#endif
    const long align_byte = 64;
#ifdef ENA_8MHVM
    char *hvm_base = (char *)0x90000000;
    q7_t * src2 = (q7_t *)hvm_base;
    addr_in_tmp_buf = (unsigned long)src2 + sizeof(*ker_weight) * out_tensor_ch * in_tensor_ch;
    addr_in_tmp_buf = nn_align(addr_in_tmp_buf, align_byte);
    dst_q31 = (q31_t *)addr_in_tmp_buf;

    //transpose the kernel_weight for matrix multiplication
    nn_mat_mul_kernel_tiling_transpose_q7(ker_weight, src2, out_tensor_ch, in_tensor_ch);

    pOut = nn_mat_mul_kernel_tiling_q7(src_buf,
                                       src2,
                                       dst_q31,
                                       pOut,
                                       in_tensor_dim_x * in_tensor_dim_y,
                                       in_tensor_ch,
                                       out_tensor_ch,
                                       pre_rshift,
                                       out_scale,
                                       post_rshift,
                                       bias,
                                       tiling_size);
#else
    addr_in_tmp_buf = (unsigned long)in_tmp_buf;
    addr_in_tmp_buf += sizeof(*ker_weight) * out_tensor_ch * in_tensor_ch;
    addr_in_tmp_buf = nn_align(addr_in_tmp_buf, align_byte);
    dst_q31 = (q31_t *)addr_in_tmp_buf;

    //transpose the kernel_weight for matrix multiplication
    nn_mat_mul_kernel_tiling_transpose_q7(ker_weight, (q7_t *)in_tmp_buf, out_tensor_ch, in_tensor_ch);

    pOut = nn_mat_mul_kernel_tiling_q7(src_buf,
                                       (q7_t *)in_tmp_buf,
                                       dst_q31,
                                       pOut,
                                       in_tensor_dim_x * in_tensor_dim_y,
                                       in_tensor_ch,
                                       out_tensor_ch,
                                       pre_rshift,
                                       out_scale,
                                       post_rshift,
                                       bias,
                                       tiling_size);
#endif
