input.new_string:
#ifdef ENA_VEC_ISA
#if defined(ENA_TILING) && (NDS_VEC_RVV_VERSION >= 1000) && defined(ENA_NDS_V5_VEC_DOT_PROD)
{
    // Runtime dispatch: query VLMAX for e8m4 to determine threshold
    long vl;
    long vlmax_e8m4;
    NDS_VEC_VSETVLI(vlmax_e8m4, reg_x0, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
    const long n_threshold = vlmax_e8m4 >> 2;

    if (out_tensor_ch < n_threshold)
    {
        // Small N: VD4DOTS GEMM path (vectorize K, no transpose)
        const long lhs_rows = in_tensor_dim_x * in_tensor_dim_y;
        const long rhs_rows = out_tensor_ch;
        const long rhs_cols = in_tensor_ch;
        const long lhs_cols_offset = in_tensor_ch;

        long max_vl_per_vg_e8m1;
        NDS_VEC_VSETVLI(max_vl_per_vg_e8m1, reg_x0, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);

        NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
        NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);   //const zero for redsum

        const q7_t *lhs = (const q7_t *)in_tensor;
        const q7_t *rhs = ker_weight;
        q7_t *dst = out_tensor;

        long rhs_rows_idx = 0;
        for (rhs_rows_idx = 0; (rhs_rows_idx + 4) <= rhs_rows; rhs_rows_idx += 4)
        {
            const q7_t *lhs_ptr = &lhs[0];
            q7_t       *dst_ptr = &dst[0];

            //load bias for 4 output channels
            NDS_VEC_VSETVLI(vl, 4, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
            const q31_t *pBias = &bias[rhs_rows_idx];
            NDS_VEC_VLE32_V(NDS_VEC_V28, pBias);

            long lhs_rows_idx = lhs_rows >> 2;
            while (lhs_rows_idx)
            {
                const q7_t *rhs_ptr  = &rhs[0];
                q7_t *rhs_ptr2 = (q7_t *)&rhs_ptr[rhs_cols];
                q7_t *rhs_ptr3 = (q7_t *)&rhs_ptr[rhs_cols * 2];
                q7_t *rhs_ptr4 = (q7_t *)&rhs_ptr[rhs_cols * 3];
                q7_t *lhs_ptr2 = (q7_t *)&lhs_ptr[lhs_cols_offset];
                q7_t *lhs_ptr3 = (q7_t *)&lhs_ptr[lhs_cols_offset * 2];
                q7_t *lhs_ptr4 = (q7_t *)&lhs_ptr[lhs_cols_offset * 3];
                long rhs_cols2 = rhs_cols;

                NDS_VEC_VSETVLI(vl, reg_x0, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0x0);
                NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0x0);

                while(rhs_cols2 >= max_vl_per_vg_e8m1)
                {
                    NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
                    NDS_VEC_VLE8_V(NDS_VEC_V16, rhs_ptr);
                    NDS_VEC_VLE8_V(NDS_VEC_V17, rhs_ptr2);
                    NDS_VEC_VLE8_V(NDS_VEC_V18, rhs_ptr3);
                    NDS_VEC_VLE8_V(NDS_VEC_V19, rhs_ptr4);
                    NDS_VEC_VLE8_V(NDS_VEC_V20, lhs_ptr);
                    NDS_VEC_VLE8_V(NDS_VEC_V21, lhs_ptr2);
                    NDS_VEC_VLE8_V(NDS_VEC_V22, lhs_ptr3);
                    NDS_VEC_VLE8_V(NDS_VEC_V23, lhs_ptr4);
                    rhs_cols2 -= vl;
                    rhs_ptr += vl;
                    rhs_ptr2 += vl;
                    rhs_ptr3 += vl;
                    rhs_ptr4 += vl;
                    lhs_ptr += vl;
                    lhs_ptr2 += vl;
                    lhs_ptr3 += vl;
                    lhs_ptr4 += vl;

                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V20);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V1, NDS_VEC_V17, NDS_VEC_V20);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V2, NDS_VEC_V18, NDS_VEC_V20);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V3, NDS_VEC_V19, NDS_VEC_V20);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V4, NDS_VEC_V16, NDS_VEC_V21);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V5, NDS_VEC_V17, NDS_VEC_V21);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V6, NDS_VEC_V18, NDS_VEC_V21);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V7, NDS_VEC_V19, NDS_VEC_V21);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V8, NDS_VEC_V16, NDS_VEC_V22);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V9, NDS_VEC_V17, NDS_VEC_V22);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V10, NDS_VEC_V18, NDS_VEC_V22);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V11, NDS_VEC_V19, NDS_VEC_V22);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V12, NDS_VEC_V16, NDS_VEC_V23);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V13, NDS_VEC_V17, NDS_VEC_V23);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V14, NDS_VEC_V18, NDS_VEC_V23);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V15, NDS_VEC_V19, NDS_VEC_V23);
                }
                while(rhs_cols2 > 0)
                {
                    long tmp_vl = rhs_cols2 + 3;
                    NDS_VEC_VSETVLI(vl, tmp_vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
                    NDS_VEC_VAND_VI(NDS_VEC_V20, NDS_VEC_V20, 0);
                    NDS_VEC_VAND_VI(NDS_VEC_V21, NDS_VEC_V21, 0);
                    NDS_VEC_VAND_VI(NDS_VEC_V22, NDS_VEC_V22, 0);
                    NDS_VEC_VAND_VI(NDS_VEC_V23, NDS_VEC_V23, 0);

                    NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
                    NDS_VEC_VLE8_V(NDS_VEC_V16, rhs_ptr);
                    NDS_VEC_VLE8_V(NDS_VEC_V17, rhs_ptr2);
                    NDS_VEC_VLE8_V(NDS_VEC_V18, rhs_ptr3);
                    NDS_VEC_VLE8_V(NDS_VEC_V19, rhs_ptr4);
                    NDS_VEC_VLE8_V(NDS_VEC_V20, lhs_ptr);
                    NDS_VEC_VLE8_V(NDS_VEC_V21, lhs_ptr2);
                    NDS_VEC_VLE8_V(NDS_VEC_V22, lhs_ptr3);
                    NDS_VEC_VLE8_V(NDS_VEC_V23, lhs_ptr4);
                    rhs_cols2 -= vl;
                    rhs_ptr += vl;
                    rhs_ptr2 += vl;
                    rhs_ptr3 += vl;
                    rhs_ptr4 += vl;
                    lhs_ptr += vl;
                    lhs_ptr2 += vl;
                    lhs_ptr3 += vl;
                    lhs_ptr4 += vl;

                    vl = (vl + 3) >> 2;
                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V20);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V1, NDS_VEC_V17, NDS_VEC_V20);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V2, NDS_VEC_V18, NDS_VEC_V20);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V3, NDS_VEC_V19, NDS_VEC_V20);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V4, NDS_VEC_V16, NDS_VEC_V21);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V5, NDS_VEC_V17, NDS_VEC_V21);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V6, NDS_VEC_V18, NDS_VEC_V21);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V7, NDS_VEC_V19, NDS_VEC_V21);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V8, NDS_VEC_V16, NDS_VEC_V22);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V9, NDS_VEC_V17, NDS_VEC_V22);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V10, NDS_VEC_V18, NDS_VEC_V22);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V11, NDS_VEC_V19, NDS_VEC_V22);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V12, NDS_VEC_V16, NDS_VEC_V23);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V13, NDS_VEC_V17, NDS_VEC_V23);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V14, NDS_VEC_V18, NDS_VEC_V23);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V15, NDS_VEC_V19, NDS_VEC_V23);
                }

                // 16 VREDSUM reductions to scalar
                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
                NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V31);
                NDS_VEC_VREDSUM_VS(NDS_VEC_V16, NDS_VEC_V1, NDS_VEC_V31);
                NDS_VEC_VREDSUM_VS(NDS_VEC_V1, NDS_VEC_V2, NDS_VEC_V31);
                NDS_VEC_VREDSUM_VS(NDS_VEC_V17, NDS_VEC_V3, NDS_VEC_V31);
                NDS_VEC_VREDSUM_VS(NDS_VEC_V2, NDS_VEC_V4, NDS_VEC_V31);
                NDS_VEC_VREDSUM_VS(NDS_VEC_V18, NDS_VEC_V5, NDS_VEC_V31);
                NDS_VEC_VREDSUM_VS(NDS_VEC_V3, NDS_VEC_V6, NDS_VEC_V31);
                NDS_VEC_VREDSUM_VS(NDS_VEC_V19, NDS_VEC_V7, NDS_VEC_V31);
                NDS_VEC_VREDSUM_VS(NDS_VEC_V4, NDS_VEC_V8, NDS_VEC_V31);
                NDS_VEC_VREDSUM_VS(NDS_VEC_V20, NDS_VEC_V9, NDS_VEC_V31);
                NDS_VEC_VREDSUM_VS(NDS_VEC_V5, NDS_VEC_V10, NDS_VEC_V31);
                NDS_VEC_VREDSUM_VS(NDS_VEC_V21, NDS_VEC_V11, NDS_VEC_V31);
                NDS_VEC_VREDSUM_VS(NDS_VEC_V6, NDS_VEC_V12, NDS_VEC_V31);
                NDS_VEC_VREDSUM_VS(NDS_VEC_V22, NDS_VEC_V13, NDS_VEC_V31);
                NDS_VEC_VREDSUM_VS(NDS_VEC_V7, NDS_VEC_V14, NDS_VEC_V31);
                NDS_VEC_VREDSUM_VS(NDS_VEC_V23, NDS_VEC_V15, NDS_VEC_V31);

                // VSLIDEUP to pack 4 results into vectors of 4 elements
                NDS_VEC_VSETVLI(vl, 4, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
                NDS_VEC_VSLIDEUP_VI(NDS_VEC_V0, NDS_VEC_V16, 1);
                NDS_VEC_VSLIDEUP_VI(NDS_VEC_V0, NDS_VEC_V1,  2);
                NDS_VEC_VSLIDEUP_VI(NDS_VEC_V0, NDS_VEC_V17, 3);
                NDS_VEC_VSLIDEUP_VI(NDS_VEC_V2, NDS_VEC_V18, 1);
                NDS_VEC_VSLIDEUP_VI(NDS_VEC_V2, NDS_VEC_V3,  2);
                NDS_VEC_VSLIDEUP_VI(NDS_VEC_V2, NDS_VEC_V19, 3);
                NDS_VEC_VSLIDEUP_VI(NDS_VEC_V4, NDS_VEC_V20, 1);
                NDS_VEC_VSLIDEUP_VI(NDS_VEC_V4, NDS_VEC_V5,  2);
                NDS_VEC_VSLIDEUP_VI(NDS_VEC_V4, NDS_VEC_V21, 3);
                NDS_VEC_VSLIDEUP_VI(NDS_VEC_V6, NDS_VEC_V22, 1);
                NDS_VEC_VSLIDEUP_VI(NDS_VEC_V6, NDS_VEC_V7,  2);
                NDS_VEC_VSLIDEUP_VI(NDS_VEC_V6, NDS_VEC_V23, 3);

                // Add bias
                NDS_VEC_VADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V28);
                NDS_VEC_VADD_VV(NDS_VEC_V2, NDS_VEC_V2, NDS_VEC_V28);
                NDS_VEC_VADD_VV(NDS_VEC_V4, NDS_VEC_V4, NDS_VEC_V28);
                NDS_VEC_VADD_VV(NDS_VEC_V6, NDS_VEC_V6, NDS_VEC_V28);

                // Sym requantize: pre_rshift -> mul -> narrow to s8
                NDS_VEC_VSRA_VX(NDS_VEC_V0, NDS_VEC_V0, pre_rshift);
                NDS_VEC_VSRA_VX(NDS_VEC_V2, NDS_VEC_V2, pre_rshift);
                NDS_VEC_VSRA_VX(NDS_VEC_V4, NDS_VEC_V4, pre_rshift);
                NDS_VEC_VSRA_VX(NDS_VEC_V6, NDS_VEC_V6, pre_rshift);

                NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, out_scale);
                NDS_VEC_VMUL_VX(NDS_VEC_V2, NDS_VEC_V2, out_scale);
                NDS_VEC_VMUL_VX(NDS_VEC_V4, NDS_VEC_V4, out_scale);
                NDS_VEC_VMUL_VX(NDS_VEC_V6, NDS_VEC_V6, out_scale);

                // Narrow e32->e16 with post_rshift (signed clip)
                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M1);
                NDS_VEC_VNCLIP_WX(NDS_VEC_V0, NDS_VEC_V0, post_rshift);
                NDS_VEC_VNCLIP_WX(NDS_VEC_V2, NDS_VEC_V2, post_rshift);
                NDS_VEC_VNCLIP_WX(NDS_VEC_V4, NDS_VEC_V4, post_rshift);
                NDS_VEC_VNCLIP_WX(NDS_VEC_V6, NDS_VEC_V6, post_rshift);

                // Narrow e16->e8 (signed clip)
                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
                NDS_VEC_VNCLIP_WX(NDS_VEC_V0, NDS_VEC_V0, 0);
                NDS_VEC_VNCLIP_WX(NDS_VEC_V2, NDS_VEC_V2, 0);
                NDS_VEC_VNCLIP_WX(NDS_VEC_V4, NDS_VEC_V4, 0);
                NDS_VEC_VNCLIP_WX(NDS_VEC_V6, NDS_VEC_V6, 0);

                // Store 4 output pixels
                NDS_VEC_VSE8_V(NDS_VEC_V0, dst_ptr);
                dst_ptr += rhs_rows;
                NDS_VEC_VSE8_V(NDS_VEC_V2, dst_ptr);
                dst_ptr += rhs_rows;
                NDS_VEC_VSE8_V(NDS_VEC_V4, dst_ptr);
                dst_ptr += rhs_rows;
                NDS_VEC_VSE8_V(NDS_VEC_V6, dst_ptr);
                dst_ptr += rhs_rows;
                lhs_ptr -= rhs_cols;
                lhs_ptr += 4 * lhs_cols_offset;
                lhs_rows_idx--;
            }

            // Left-over lhs rows (1-3 pixels)
            long rest_lhs_row = lhs_rows & 3;
            while(rest_lhs_row-- > 0)
            {
                const q7_t *rhs_ptr  = &rhs[0];
                q7_t *rhs_ptr2 = (q7_t *)&rhs_ptr[rhs_cols];
                q7_t *rhs_ptr3 = (q7_t *)&rhs_ptr[rhs_cols * 2];
                q7_t *rhs_ptr4 = (q7_t *)&rhs_ptr[rhs_cols * 3];
                long rhs_cols2 = rhs_cols;

                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M2);
                NDS_VEC_VAND_VI(NDS_VEC_V12, NDS_VEC_V12, 0x0);
                NDS_VEC_VAND_VI(NDS_VEC_V14, NDS_VEC_V14, 0x0);
                NDS_VEC_VAND_VI(NDS_VEC_V16, NDS_VEC_V16, 0x0);
                NDS_VEC_VAND_VI(NDS_VEC_V18, NDS_VEC_V18, 0x0);

                while(rhs_cols2 >= max_vl_per_vg_e8m1)
                {
                    NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
                    NDS_VEC_VLE8_V(NDS_VEC_V4, rhs_ptr);
                    NDS_VEC_VLE8_V(NDS_VEC_V6, rhs_ptr2);
                    NDS_VEC_VLE8_V(NDS_VEC_V8, rhs_ptr3);
                    NDS_VEC_VLE8_V(NDS_VEC_V10, rhs_ptr4);
                    NDS_VEC_VLE8_V(NDS_VEC_V20, lhs_ptr);
                    rhs_cols2 -= vl;
                    rhs_ptr += vl;
                    rhs_ptr2 += vl;
                    rhs_ptr3 += vl;
                    rhs_ptr4 += vl;
                    lhs_ptr += vl;

                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M2);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V12, NDS_VEC_V4, NDS_VEC_V20);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V14, NDS_VEC_V6, NDS_VEC_V20);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V16, NDS_VEC_V8, NDS_VEC_V20);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V18, NDS_VEC_V10, NDS_VEC_V20);
                }
                while(rhs_cols2 > 0)
                {
                    long tmp_vl = rhs_cols2 + 3;
                    NDS_VEC_VSETVLI(vl, tmp_vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
                    NDS_VEC_VAND_VI(NDS_VEC_V20, NDS_VEC_V20, 0);

                    NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
                    NDS_VEC_VLE8_V(NDS_VEC_V4, rhs_ptr);
                    NDS_VEC_VLE8_V(NDS_VEC_V6, rhs_ptr2);
                    NDS_VEC_VLE8_V(NDS_VEC_V8, rhs_ptr3);
                    NDS_VEC_VLE8_V(NDS_VEC_V10, rhs_ptr4);
                    NDS_VEC_VLE8_V(NDS_VEC_V20, lhs_ptr);
                    rhs_cols2 -= vl;
                    rhs_ptr += vl;
                    rhs_ptr2 += vl;
                    rhs_ptr3 += vl;
                    rhs_ptr4 += vl;
                    lhs_ptr += vl;

                    vl = (vl + 3) >> 2;
                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M2);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V12, NDS_VEC_V4, NDS_VEC_V20);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V14, NDS_VEC_V6, NDS_VEC_V20);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V16, NDS_VEC_V8, NDS_VEC_V20);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V18, NDS_VEC_V10, NDS_VEC_V20);
                }

                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M2);
                NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V12, NDS_VEC_V31);
                NDS_VEC_VREDSUM_VS(NDS_VEC_V2, NDS_VEC_V14, NDS_VEC_V31);
                NDS_VEC_VREDSUM_VS(NDS_VEC_V1, NDS_VEC_V16, NDS_VEC_V31);
                NDS_VEC_VREDSUM_VS(NDS_VEC_V3, NDS_VEC_V18, NDS_VEC_V31);

                NDS_VEC_VSETVLI(vl, 4, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
                NDS_VEC_VSLIDEUP_VI(NDS_VEC_V0, NDS_VEC_V2, 1);
                NDS_VEC_VSLIDEUP_VI(NDS_VEC_V0, NDS_VEC_V1, 2);
                NDS_VEC_VSLIDEUP_VI(NDS_VEC_V0, NDS_VEC_V3, 3);

                // Add bias
                NDS_VEC_VADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V28);

                // Sym requantize
                NDS_VEC_VSRA_VX(NDS_VEC_V0, NDS_VEC_V0, pre_rshift);
                NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, out_scale);

                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M1);
                NDS_VEC_VNCLIP_WX(NDS_VEC_V0, NDS_VEC_V0, post_rshift);
                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
                NDS_VEC_VNCLIP_WX(NDS_VEC_V0, NDS_VEC_V0, 0);

                NDS_VEC_VSE8_V(NDS_VEC_V0, dst_ptr);
                dst_ptr += rhs_rows;
                lhs_ptr -= rhs_cols;
                lhs_ptr += lhs_cols_offset;
            }

            rhs += 4 * rhs_cols;
            dst += 4;
        }

        // Remainder output channels (1-3)
        for (; rhs_rows_idx < rhs_rows; rhs_rows_idx++)
        {
            const q7_t *lhs_ptr = &lhs[0];
            q7_t *dst_ptr = &dst[0];

            //load bias for 1 channel
            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
            const q31_t *pBias1 = &bias[rhs_rows_idx];
            NDS_VEC_VLE32_V(NDS_VEC_V28, pBias1);

            for (long lhs_rows_idx2 = 0; lhs_rows_idx2 < lhs_rows; ++lhs_rows_idx2)
            {
                const q7_t *rhs_ptr = &rhs[0];
                long rhs_cols2 = rhs_cols;

                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0x0);

                while(rhs_cols2 >= max_vl_per_vg_e8m1)
                {
                    NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VLE8_V(NDS_VEC_V8, rhs_ptr);
                    NDS_VEC_VLE8_V(NDS_VEC_V16, lhs_ptr);
                    rhs_ptr += vl;
                    lhs_ptr += vl;
                    rhs_cols2 -= vl;

                    vl >>= 2;
                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
                }
                while(rhs_cols2 > 0)
                {
                    long tmp_vl = rhs_cols2 + 3;
                    NDS_VEC_VSETVLI(vl, tmp_vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VAND_VI(NDS_VEC_V16, NDS_VEC_V16, 0);

                    NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VLE8_V(NDS_VEC_V8, rhs_ptr);
                    NDS_VEC_VLE8_V(NDS_VEC_V16, lhs_ptr);
                    rhs_ptr += vl;
                    lhs_ptr += vl;
                    rhs_cols2 -= vl;

                    vl = (vl + 3) >> 2;
                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
                }

                lhs_ptr -= rhs_cols;
                lhs_ptr += lhs_cols_offset;

                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V28);

                // Scalar requantize
                long res00;
                NDS_VEC_VMV_X_S(res00, NDS_VEC_V0);
                res00 = (res00 >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
                dst_ptr[0] = (q7_t)NDS_ISA_SATS((res00 >> post_rshift), 8);
                dst_ptr += rhs_rows;
            }
            rhs += rhs_cols;
            dst++;
        }
    }
    else
    {
        // Large N: fall through to tiling GEMM path
        uint32_t tiling_size = 256;
        unsigned long addr_in_tmp_buf;
        q7_t *pOut = out_tensor;
        q7_t *src_buf = (q7_t *) in_tensor;
        q31_t *dst_q31;

        const long align_byte = 64;
        addr_in_tmp_buf = (unsigned long)in_tmp_buf;
        addr_in_tmp_buf += sizeof(*ker_weight) * out_tensor_ch * in_tensor_ch;
        addr_in_tmp_buf = nn_align(addr_in_tmp_buf, align_byte);
        dst_q31 = (q31_t *)addr_in_tmp_buf;

        nn_mat_mul_kernel_tiling_transpose_q7(ker_weight, (q7_t *)in_tmp_buf, out_tensor_ch, in_tensor_ch);

        pOut = nn_mat_mul_kernel_tiling_q7(src_buf,
                                           (q7_t *)in_tmp_buf,
                                           dst_q31,
                                           pOut,
                                           in_tensor_dim_x * in_tensor_dim_y,
                                           in_tensor_ch,
                                           out_tensor_ch,
                                           pre_rshift,
                                           out_scale,
                                           post_rshift,
                                           bias,
                                           tiling_size);
    }
}
#elif (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_TILING)
    //cache is 512KB, type is q7
