#ifdef ENA_VEC_ISA
#if defined(ENA_TILING) && (NDS_VEC_RVV_VERSION >= 1000) && defined(ENA_NDS_V5_VEC_DOT_PROD)
{
    long vl;
    long vlmax_e8m4;
    NDS_VEC_VSETVLI(vlmax_e8m4, reg_x0, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
    const long n_threshold = vlmax_e8m4 >> 2;

    if (out_tensor_ch < n_threshold)
    {
        const long lhs_rows = in_tensor_dim_x * in_tensor_dim_y;
        const long rhs_rows = out_tensor_ch;
        const long rhs_cols = in_tensor_ch;
        const long lhs_cols_offset = in_tensor_ch;

        long max_vl_per_vg_e8m1;
        NDS_VEC_VSETVLI(max_vl_per_vg_e8m1, reg_x0, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);

        NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
        NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);

        const u8_t *lhs = (const u8_t *)in_tensor;
        const q7_t *rhs = ker_weight;
