                q7_t *rhs_ptr2 = (q7_t *)&rhs_ptr[rhs_cols];
                q7_t *rhs_ptr3 = (q7_t *)&rhs_ptr[rhs_cols * 2];
                q7_t *rhs_ptr4 = (q7_t *)&rhs_ptr[rhs_cols * 3];
                u8_t *lhs_ptr2 = (u8_t *)&lhs_ptr[lhs_cols_offset];
                u8_t *lhs_ptr3 = (u8_t *)&lhs_ptr[lhs_cols_offset * 2];
                u8_t *lhs_ptr4 = (u8_t *)&lhs_ptr[lhs_cols_offset * 3];
                long rhs_cols2 = rhs_cols;

                NDS_VEC_VSETVLI(vl, reg_x0, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
