                NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0x0);

                while(rhs_cols2 >= max_vl_per_vg_e8m1)
                {
                    NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
                    NDS_VEC_VLE8_V(NDS_VEC_V16, rhs_ptr);
                    NDS_VEC_VLE8_V(NDS_VEC_V17, rhs_ptr2);
                    NDS_VEC_VLE8_V(NDS_VEC_V18, rhs_ptr3);
                    NDS_VEC_VLE8_V(NDS_VEC_V19, rhs_ptr4);
