                    rhs_cols2 -= vl;
                    rhs_ptr += vl; rhs_ptr2 += vl; rhs_ptr3 += vl; rhs_ptr4 += vl;
                    lhs_ptr += vl; lhs_ptr2 += vl; lhs_ptr3 += vl; lhs_ptr4 += vl;

                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V20);
                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V1, NDS_VEC_V17, NDS_VEC_V20);
