                }
                while(rhs_cols2 > 0)
                {
                    long tmp_vl = rhs_cols2 + 3;
                    NDS_VEC_VSETVLI(vl, tmp_vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
                    NDS_VEC_VAND_VI(NDS_VEC_V20, NDS_VEC_V20, 0);
                    NDS_VEC_VAND_VI(NDS_VEC_V21, NDS_VEC_V21, 0);
                    NDS_VEC_VAND_VI(NDS_VEC_V22, NDS_VEC_V22, 0);
                    NDS_VEC_VAND_VI(NDS_VEC_V23, NDS_VEC_V23, 0);

                    NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
                    NDS_VEC_VLE8_V(NDS_VEC_V16, rhs_ptr);
