                    NDS_VEC_VLE8_V(NDS_VEC_V20, lhs_ptr);
                    NDS_VEC_VLE8_V(NDS_VEC_V21, lhs_ptr2);
                    NDS_VEC_VLE8_V(NDS_VEC_V22, lhs_ptr3);
                    NDS_VEC_VLE8_V(NDS_VEC_V23, lhs_ptr4);
