                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V4, NDS_VEC_V16, NDS_VEC_V21);
                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V5, NDS_VEC_V17, NDS_VEC_V21);
                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V6, NDS_VEC_V18, NDS_VEC_V21);
                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V7, NDS_VEC_V19, NDS_VEC_V21);
                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V8, NDS_VEC_V16, NDS_VEC_V22);
                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V9, NDS_VEC_V17, NDS_VEC_V22);
                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V10, NDS_VEC_V18, NDS_VEC_V22);
                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V11, NDS_VEC_V19, NDS_VEC_V22);
                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V12, NDS_VEC_V16, NDS_VEC_V23);
                    NDS_VEC_VD4DOTSU_VV(NDS_VEC_V13, NDS_VEC_V17, NDS_VEC_V23);
